const { DynamoDBClient } = require('@aws-sdk/client-dynamodb');
const { DynamoDBDocumentClient, PutCommand, GetCommand } = require('@aws-sdk/lib-dynamodb');
const crypto = require('crypto');

const client = new DynamoDBClient({});
const docClient = DynamoDBDocumentClient.from(client);

const TABLE_NAME = process.env.USERS_TABLE || 'Users';

// --- Security Utilities ---

function hashPassword(password, salt) {
  return new Promise((resolve, reject) => {
    crypto.scrypt(password, salt, 64, { N: 32768, r: 8, p: 1 }, (err, derivedKey) => {
      if (err) reject(err);
      resolve(derivedKey.toString('hex'));
    });
  });
}

function generateSalt() {
  return crypto.randomBytes(32).toString('hex');
}

function generateUserId() {
  return crypto.randomUUID();
}

function validateEmail(email) {
  if (typeof email !== 'string') return false;
  if (email.length > 254) return false;
  const emailRegex = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$/;
  return emailRegex.test(email);
}

function validatePassword(password) {
  if (typeof password !== 'string') return false;
  if (password.length < 12 || password.length > 128) return false;
  const hasUppercase = /[A-Z]/.test(password);
  const hasLowercase = /[a-z]/.test(password);
  const hasDigit = /[0-9]/.test(password);
  const hasSpecial = /[^a-zA-Z0-9]/.test(password);
  return hasUppercase && hasLowercase && hasDigit && hasSpecial;
}

function sanitizeInput(input) {
  if (typeof input !== 'string') return '';
  return input.trim();
}

function buildResponse(statusCode, body) {
  return {
    statusCode,
    headers: {
      'Content-Type': 'application/json',
      'Strict-Transport-Security': 'max-age=63072000; includeSubDomains; preload',
      'X-Content-Type-Options': 'nosniff',
      'X-Frame-Options': 'DENY',
      'Cache-Control': 'no-store',
      'Pragma': 'no-cache',
    },
    body: JSON.stringify(body),
  };
}

// Constant-time delay to mitigate timing-based user enumeration
async function constantTimeDelay(startTime, minDurationMs = 300) {
  const elapsed = Date.now() - startTime;
  const remaining = minDurationMs - elapsed;
  if (remaining > 0) {
    await new Promise((resolve) => setTimeout(resolve, remaining));
  }
}

// --- Rate Limiting (per-IP, using DynamoDB) ---

const RATE_LIMIT_TABLE = process.env.RATE_LIMIT_TABLE || 'RateLimits';
const RATE_LIMIT_WINDOW_SECONDS = 300; // 5 minutes
const RATE_LIMIT_MAX_REQUESTS = 5;

async function checkRateLimit(sourceIp) {
  const now = Math.floor(Date.now() / 1000);
  const windowStart = now - RATE_LIMIT_WINDOW_SECONDS;

  try {
    const result = await docClient.send(new GetCommand({
      TableName: RATE_LIMIT_TABLE,
      Key: { pk: `IP#${sourceIp}` },
    }));

    if (result.Item) {
      // Filter timestamps within the current window
      const recentRequests = (result.Item.timestamps || []).filter(ts => ts > windowStart);

      if (recentRequests.length >= RATE_LIMIT_MAX_REQUESTS) {
        return { allowed: false, retryAfterSeconds: RATE_LIMIT_WINDOW_SECONDS };
      }

      // Update with new timestamp, pruning old ones
      recentRequests.push(now);
      await docClient.send(new PutCommand({
        TableName: RATE_LIMIT_TABLE,
        Item: {
          pk: `IP#${sourceIp}`,
          timestamps: recentRequests,
          ttl: now + RATE_LIMIT_WINDOW_SECONDS * 2,
        },
      }));
    } else {
      await docClient.send(new PutCommand({
        TableName: RATE_LIMIT_TABLE,
        Item: {
          pk: `IP#${sourceIp}`,
          timestamps: [now],
          ttl: now + RATE_LIMIT_WINDOW_SECONDS * 2,
        },
      }));
    }

    return { allowed: true };
  } catch (err) {
    // If rate limit check fails, log but allow the request (fail open for availability)
    // In production you may want to fail closed instead
    console.error('Rate limit check error:', err.message);
    return { allowed: true };
  }
}

// --- Main Handler ---

exports.handler = async (event) => {
  const startTime = Date.now();

  try {
    // Only allow POST
    if (event.httpMethod !== 'POST') {
      return buildResponse(405, { message: 'Method not allowed' });
    }

    // Only allow the registration path
    if (event.resource !== '/register' && event.path !== '/register') {
      return buildResponse(404, { message: 'Not found' });
    }

    // Rate limiting by source IP
    const sourceIp = event.requestContext?.identity?.sourceIp || 'unknown';
    const rateLimitResult = await checkRateLimit(sourceIp);
    if (!rateLimitResult.allowed) {
      await constantTimeDelay(startTime);
      return buildResponse(429, {
        message: 'Too many requests. Please try again later.',
        retryAfterSeconds: rateLimitResult.retryAfterSeconds,
      });
    }

    // Parse and validate request body
    let body;
    try {
      body = JSON.parse(event.body || '{}');
    } catch {
      await constantTimeDelay(startTime);
      return buildResponse(400, { message: 'Invalid JSON in request body' });
    }

    // Reject unexpected fields (mass assignment protection)
    const allowedFields = new Set(['email', 'password']);
    const providedFields = Object.keys(body);
    const unexpectedFields = providedFields.filter(f => !allowedFields.has(f));
    if (unexpectedFields.length > 0) {
      await constantTimeDelay(startTime);
      return buildResponse(400, { message: 'Unexpected fields in request body' });
    }

    // Limit body size (defense in depth beyond API Gateway limits)
    if (event.body && event.body.length > 2048) {
      await constantTimeDelay(startTime);
      return buildResponse(400, { message: 'Request body too large' });
    }

    const email = sanitizeInput(body.email);
    const password = body.password; // Don't trim passwords - whitespace may be intentional

    // Validate email
    if (!email) {
      await constantTimeDelay(startTime);
      return buildResponse(400, { message: 'Email is required' });
    }
    if (!validateEmail(email)) {
      await constantTimeDelay(startTime);
      return buildResponse(400, { message: 'Invalid email format' });
    }

    // Validate password
    if (!password || typeof password !== 'string') {
      await constantTimeDelay(startTime);
      return buildResponse(400, {
        message: 'Password is required',
      });
    }
    if (!validatePassword(password)) {
      await constantTimeDelay(startTime);
      return buildResponse(400, {
        message: 'Password must be 12-128 characters and include uppercase, lowercase, digit, and special character',
      });
    }

    // Normalize email to lowercase for consistent lookups
    const normalizedEmail = email.toLowerCase();

    // Hash password with unique salt
    const salt = generateSalt();
    const hashedPassword = await hashPassword(password, salt);

    const userId = generateUserId();
    const now = new Date().toISOString();

    // Create user with conditional expression to prevent duplicates
    // Using email as partition key with a condition to atomically check existence
    try {
      await docClient.send(new PutCommand({
        TableName: TABLE_NAME,
        Item: {
          pk: `USER#${normalizedEmail}`,
          sk: 'PROFILE',
          userId,
          email: normalizedEmail,
          passwordHash: hashedPassword,
          salt,
          hashAlgorithm: 'scrypt',
          createdAt: now,
          updatedAt: now,
          emailVerified: false,
          accountStatus: 'PENDING_VERIFICATION',
        },
        ConditionExpression: 'attribute_not_exists(pk)',
      }));
    } catch (err) {
      if (err.name === 'ConditionalCheckFailedException') {
        // Return generic message to prevent user enumeration
        await constantTimeDelay(startTime);
        return buildResponse(409, {
          message: 'Unable to create account. An account with this email may already exist.',
        });
      }
      throw err;
    }

    // Log registration event (without sensitive data)
    console.log(JSON.stringify({
      event: 'USER_REGISTERED',
      userId,
      email: normalizedEmail,
      timestamp: now,
      sourceIp,
    }));

    await constantTimeDelay(startTime);

    return buildResponse(201, {
      message: 'Account created successfully. Please verify your email.',
      userId,
      email: normalizedEmail,
    });

  } catch (err) {
    // Log error details server-side but return generic message to client
    console.error('Registration error:', {
      errorMessage: err.message,
      errorName: err.name,
      timestamp: new Date().toISOString(),
    });

    await constantTimeDelay(startTime);

    return buildResponse(500, {
      message: 'An internal error occurred. Please try again later.',
    });
  }
};

